INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('ACIEXC', 'Acidity - exchangeable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Aciexc', 'Exchangeable acidity represents the amount of hydrogen (H⁺) and aluminum (Al³⁺) ions adsorbed onto soil particles that can be exchanged with the soil solution. It is a key factor in determining soil liming requirements and improving nutrient availability in acidic soils. Source: Brady & Weil (2017).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('ALUEXC', 'Aluminium (Al) exchangeable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Aluexc', 'Aluminium ions bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('ALUTOT', 'Aluminium (Al) total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Alutot', 'Total concentration of aluminium in the soil, including both soluble and insoluble forms, typically measured after complete digestion of the soil sample.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('AVAVOL', 'Available water capacity - volumetric (FC to WP)', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Avavol', 'Available water capacity (AWC) measures the volume of water soil can retain between field capacity and the permanent wilting point. It represents the water accessible to plants for uptake. High AWC supports better plant growth, while low AWC may necessitate irrigation. Source: USDA NRCS.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('BASCAL', 'Base saturation - calculated', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Bascal', 'Base saturation represents the percentage of the soil''s cation exchange capacity (CEC) occupied by basic cations such as calcium (Ca²⁺), magnesium (Mg²⁺), potassium (K⁺), and sodium (Na⁺). Higher base saturation typically correlates with higher fertility and a greater ability to supply essential nutrients to plants. This parameter also influences soil pH buffering capacity. Source: Brady & Weil (2017).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('BOREXT', 'Boron (B) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Borext', 'Boron bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('BORTOT', 'Boron (B) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Bortot', 'Total boron includes all boron forms in soil, crucial for plant cell wall formation and reproductive processes. Deficiency can impair growth, while toxicity is a risk in arid soils or with excessive irrigation. Source: Havlin et al. (2014).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('BULDFINE', 'Bulk Density of the fine earth fraction', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-BulDfine', 'This parameter measures the bulk density of the soil fraction smaller than 2 mm (excluding rocks and coarse fragments). It is used to assess the physical properties of soil related to root growth, water movement, and compaction. Source: Soil Science Society of America.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('CAD', 'Cadmium (Cd)', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Cad', 'Cadmium is a heavy metal present in trace amounts in soils, often introduced through industrial pollution or phosphate fertilizers. It is toxic to plants, animals, and humans even at low concentrations. Monitoring cadmium levels is crucial to ensure soil safety and reduce contamination risks in the food chain. Source: Sparks, D.L. (2003).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('CALEXC', 'Calcium (Ca++) - exchangeable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Calexc', 'Calcium bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('CALEXT', 'Calcium (Ca++) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Calext', 'Calcium bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('CALTOT', 'Calcium (Ca++) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Caltot', 'Total calcium in soil includes all forms, from exchangeable calcium to calcium in minerals. It is essential for plant cell wall structure, enzyme activation, and soil aggregation. Calcium levels influence soil pH and nutrient availability. Source: Havlin et al. (2014).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('CEC', 'Cation exchange capacity (CEC)', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-CEC', 'CEC measures the soil’s ability to hold and exchange positively charged ions (cations). It is a critical indicator of soil fertility, as higher CEC values imply greater capacity to retain essential nutrients like calcium, magnesium, and potassium. Clayey and organic-rich soils typically exhibit higher CEC. Source: Soil Science Society of America.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('COPEXT', 'Copper (Cu) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Copext', 'Copper bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('COPTOT', 'Copper (Cu) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Coptot', 'Total copper comprises all soil copper, including bound and free forms. Copper is vital for plant enzyme activation and metabolic processes. Deficiencies can lead to reduced growth and yields, while excess copper may inhibit root development. Source: Soil Science Society of America.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('ECEC', 'Cation exchange capacity effective (ECEC)', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-ECEC', 'ECEC is the sum of exchangeable cations in soil at its natural pH. It provides a measure of the soil’s fertility under acidic conditions, as it considers both base cations and exchangeable aluminum. Source: Brady & Weil (2017).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('ELECCOND', 'Electrical conductivity', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Eleccond', 'Electrical conductivity (EC) measures the ability of soil to conduct an electrical current, which is directly related to the concentration of soluble salts. It is an essential indicator of soil salinity and is used to assess soil''s suitability for crop growth. High EC levels can reduce plant water uptake and affect germination, while low levels indicate low salinity and better soil health. Source: USDA NRCS.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('HYDEXC', 'Hydrogen (H+) - exchangeable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Hydexc', 'Hydrogen ions bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('IROEXT', 'Iron (Fe) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Iroext', 'Iron bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('IROTOT', 'Iron (Fe) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Irotot', 'Total iron includes all iron forms in the soil, from soluble ferrous iron (Fe²⁺) to insoluble ferric iron (Fe³⁺). Iron is essential for plant chlorophyll synthesis and various enzymatic reactions. Deficiency, often seen in alkaline soils, results in chlorosis, while excessive iron can cause toxicity in acidic soils. Source: Soil Chemistry by Bohn et al.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('MAGEXC', 'Magnesium (Mg++) - exchangeable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Magexc', 'Magnesium bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('MAGEXT', 'Magnesium (Mg) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Magext', 'Magnesium bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('MAGTOT', 'Magnesium (Mg) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Magtot', 'Total magnesium in soil includes exchangeable, soluble, and mineral-bound forms. Magnesium is essential for chlorophyll synthesis, enzyme activation, and nutrient transport in plants. Its availability is influenced by soil pH and texture. Source: Havlin et al. (2014).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('MANTOT', 'Manganese (Mn) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Mantot', 'Total manganese refers to all forms of manganese in the soil, which is critical for photosynthesis, enzyme activation, and nitrogen metabolism in plants. Manganese deficiencies or toxicities are influenced by soil pH, with deficiencies occurring in high-pH soils and toxicities in low-pH, waterlogged soils.  Source: Brady & Weil (2017).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('MANEXT', 'Manganese (Mn) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Manext', 'Manganese bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('MOL', 'Molybdenum', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Mol', 'Molybdenum is a micronutrient essential for plant enzymes involved in nitrogen fixation and nitrate reduction. Deficiency, often observed in acidic soils, can lead to stunted growth and poor nitrogen utilization. Its availability increases with higher pH, making liming a common solution for molybdenum deficiencies. Source: Havlin et al. (2014).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('PHOEXT', 'Phosphorus (P) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Phoext', 'Phosphorus bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('PHOTOT', 'Phosphorus (P) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Photot', 'Total phosphorus includes all forms of phosphorus in the soil, both organic and inorganic. While only a fraction is plant-available, total phosphorus serves as a long-term reserve for crop nutrition. Adequate phosphorus levels are crucial for energy transfer, photosynthesis, and root development in plants. Source: Soil Chemistry by Bohn et al.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('POTEXC', 'Potassium (K+) - exchangeable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Potexc', 'Potassium bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('POTEXT', 'Potassium (K) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Potext', 'Potassium bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('POTTOT', 'Potassium (K) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Pottot', 'Total potassium includes all forms of potassium in soil, such as mineral-bound, exchangeable, and water-soluble potassium. It plays a vital role in plant growth by regulating water balance, enzyme activation, and photosynthesis. While only a fraction of total potassium is readily available to plants, it serves as a reserve to replenish exchangeable potassium over time. Adequate potassium levels improve crop yield, quality, and resistance to stress. Source: Soil Science Society of America.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('SODEXP', 'Sodium (Na+) - exchangeable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Sodexp', 'Sodium bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('SODEXT', 'Sodium (Na) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Sodext', 'Sodium bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('SODTOT', 'Sodium (Na) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Sodtot', 'Total sodium includes all sodium present in soil, both soluble and bound. Excess sodium can lead to sodicity, which disrupts soil structure, reduces permeability, and impairs plant growth. Monitoring sodium levels is crucial for managing soil salinity in arid and irrigated regions. Source: Bohn, H.L., et al. (2001). Soil Chemistry.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('SULEXT', 'Sulfur (S) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Sulext', 'Sulfur bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('SULTOT', 'Sulfur (S) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Sultot', 'Total sulfur in soil includes both organic and inorganic forms, such as sulfates and sulfur in organic matter. Sulfur is essential for protein synthesis and enzyme functions in plants. Deficiency leads to stunted growth and yellowing of leaves. Total sulfur provides insight into the soil''s potential to release plant-available sulfur over time, critical for sustaining crop health. Source: Havlin, J.L., et al. (2014). Soil Fertility and Fertilizers.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('ZINEXT', 'Zinc (Zn) - extractable', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Zinext', 'Zinc bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('ZIN', 'Zinc (Zn)', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Zin', 'Zinc is a micronutrient essential for plant enzyme systems, protein synthesis, and growth regulation. Deficiency is common in calcareous soils and results in stunted growth and chlorosis. Zinc fertilizers or soil pH adjustments can address deficiencies. Source: Havlin et al. (2014).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('COAFRA', 'CoaFra', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-CoaFra', '') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('CARINORG', 'Carbon (C) - inorganic', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Carinorg', 'Inorganic carbon in soil primarily consists of carbonates like calcium carbonate and magnesium carbonate. It contributes to soil pH buffering and is a significant feature of arid and calcareous soils. Excess inorganic carbon can immobilize certain nutrients, requiring careful management in agricultural systems. Source: Soil Science Society of America.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('CARORG', 'Carbon (C) - organic', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Carorg', 'Organic carbon refers to the carbon component of soil organic matter, derived from decomposed plant and microbial residues. It serves as a key energy source for soil microbes and influences nutrient cycling, soil structure, and water retention. Organic carbon is a primary indicator of soil fertility and health. Source: Brady & Weil (2017).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('CARTOT', 'Carbon (C) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Cartot', 'Total carbon in soil includes both organic carbon (from plant and microbial residues) and inorganic carbon (primarily carbonates). It is a fundamental component of soil organic matter, influencing soil fertility, structure, and water retention. High carbon levels are associated with better soil health and productivity. Source: USDA NRCS.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('GYP', 'Gypsum content - weight', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Gyp', 'The gypsum content, expressed as weight, refers to the soil’s calcium sulfate levels. Gypsum improves soil structure, alleviates sodicity, and enhances water infiltration. It is commonly applied to saline-sodic soils for reclamation. Source: FAO Soil Bulletin.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('HYDCOND', 'Hydraulic conductivity', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Hydcond', 'Hydraulic conductivity refers to the rate at which water moves through soil pores under a unit hydraulic gradient. It reflects the soil''s ability to transmit water, influenced by texture, structure, and porosity. Soils with high hydraulic conductivity, like sandy soils, allow rapid water movement, while clayey soils exhibit slower water flow. This property is critical for understanding water infiltration, drainage, and irrigation management. Source: Brady, N.C., & Weil, R.R. (2017). The Nature and Properties of Soils.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('NITTOT', 'Nitrogen (N) - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Nittot', 'Total nitrogen encompasses all nitrogen forms in soil, including organic nitrogen in humus and inorganic nitrogen such as ammonium (NH₄⁺) and nitrate (NO₃⁻). Nitrogen is essential for plant growth, being a vital component of amino acids, proteins, and chlorophyll. Total nitrogen is a key indicator of soil fertility and its capacity to sustain long-term crop productivity. Source: Brady & Weil (2017).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('ORGMAT', 'Organic matter', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Orgmat', 'Soil organic matter is composed of decomposed plant and animal residues, living soil organisms, and humus. It improves soil structure, water retention, nutrient supply, and microbial activity, making it critical for sustainable agriculture and soil health. Source: Brady & Weil (2017).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('PH', 'pH - Hydrogen potential', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-pH', 'Soil pH measures the concentration of hydrogen ions (H⁺) in the soil solution, indicating its acidity or alkalinity on a scale from 1 to 14. Neutral soils have a pH of 7, while values below 7 are acidic and above are alkaline. Soil pH significantly affects nutrient availability, microbial activity, and plant growth. For instance, nutrients like phosphorus are most available in a pH range of 6 to 7. Lime or sulfur applications can adjust soil pH to optimize conditions for crops. Source: USDA Natural Resources Conservation Service (NRCS).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('PHORET', 'Phosphorus (P) - retention', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Phoret', 'Phosphorus retention measures a soil''s capacity to adsorb and hold phosphorus, influenced by soil texture, pH, and mineralogy. While high retention reduces leaching, it may also limit phosphorus availability to plants. Understanding phosphorus retention helps optimize fertilization and minimize environmental impacts. Source: Brady & Weil (2017).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('POR', 'Porosity', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Por', 'Porosity refers to the percentage of soil volume occupied by pores or voids, which hold air and water. It directly impacts water infiltration, drainage, and root growth. Soils with high porosity are better suited for crop cultivation, as they provide good aeration and water availability. Source: Brady & Weil (2017).') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('SOLSAL', 'Soluble salts', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Solsal', 'Soluble salts refer to dissolved salts in the soil solution, primarily composed of sodium, calcium, magnesium, chloride, and sulfate ions. Excessive soluble salts cause salinity, which can impair plant water uptake and lead to osmotic stress. EC testing helps monitor salinity levels for effective management. Source: Soil Science Society of America.') ON CONFLICT DO NOTHING;
INSERT INTO soil_data.property_num (property_num_id, property_name, uri, definition) VALUES ('CCETOT', 'Calcium carbonate equivalent - total', 'http://w3id.org/glosis/model/codelists/physioChemicalPropertyCode-Ccetot', 'The total calcium carbonate equivalent measures the full capacity of soil to neutralize acidity, considering all forms of carbonate and bicarbonate minerals. It is essential for managing soil pH and nutrient availability in acidic soils. Source: FAO Soil Bulletin.') ON CONFLICT DO NOTHING;
